async (page) => {
  // Close welcome dialog if present
  await page.evaluate(() => { const btn = document.getElementById('close-welcome'); if (btn) btn.click(); });
  await page.waitForTimeout(500);

  // Set Hack attack style
  await page.evaluate(() => window.game.player.setAttackStyle(0));

  // Check current skills
  const skills = await page.evaluate(() => {
    const p = window.game.player;
    if (!p || !p.skills) return {};
    const result = {};
    ['Lumberjacking','Accuracy','Archery','Health','Magic','Mining','Strength','Defense'].forEach((name, i) => {
      const idx = [0,1,2,3,4,5,6,7][i];
      const s = p.skills[idx];
      if (s) result[name] = { level: s.level, exp: s.experience };
    });
    return result;
  });

  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState || {}));
  const parsed = JSON.parse(state);
  return JSON.stringify({ skills, pos: parsed.player_position, hp: `${parsed.player_stats?.hp}/${parsed.player_stats?.max_hp}`, level: parsed.player_stats?.level });
}

async (page) => {
  // Walk directly to Village Girl at (136, 146)
  await page.evaluate(({x, y}) => window.__clickTile(x, y), {x: 137, y: 146});
  await page.waitForTimeout(3000);
  const state = await page.evaluate(() => {
    const gs = window.__latestGameState;
