async (page) => {
  const step = async (x, y, wait=3500) => {
    await page.evaluate(({x,y}) => window.__clickTile(x, y), {x, y});
    await page.waitForTimeout(wait);
    const s = await page.evaluate(() => window.__latestGameState);
    if (!s) return '?';
    return `(${s.player_position.x},${s.player_position.y}) HP:${s.player_stats.hp}`;
  };

  // Navigate west-south to x=265-268 corridor  
  // y=158 at x=268 is open; then south to y=163+ at x=265
  const p1 = await step(268, 158);  // west 7, south 4 (Vulture at 280,158 - stay west)
  const p2 = await step(265, 163);  // continue southwest

  const s = await page.evaluate(() => window.__latestGameState);
  return JSON.stringify({p1, p2, hp: s?.player_stats?.hp, pos: s ? `(${s.player_position.x},${s.player_position.y})` : '?'});
}
